VALUES
  ('elementary-6e11b43e-moex-00059', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-ea33d64d', 'sub-elementary-6e11b43e-02', NULL, 'single_choice', '為發展及厚植原住民族知識體系，中央原住民族主管機關應會商教育、科技、文化等主管機關，建構原住 民族知識體系中長程計畫，並積極獎勵原住民族學術及各原住民族知識研究。前項中長程計畫，至少每幾 年應通盤檢討一次，並公告之？', '["3年", "5年", "7年", "10年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:55+00:00", "source_pdf_sha1": "c52cfd10ec2a", "answer_pdf_sha1": "02f86109cb69", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00060', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-ea33d64d', 'sub-elementary-6e11b43e-02', NULL, 'single_choice', '依照原住民族教育法規定，中央教育主管機關與中央原住民族主管機關應共同召開原住民族教育政策會， 進行原住民族教育政策規劃之諮詢。前項政策會委員組成的比例，具原住民身分者不得少於多少，並應兼 顧族群比率？', '["二分之一", "三分之二", "四分之三", "五分之三"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:55+00:00", "source_pdf_sha1": "c52cfd10ec2a", "answer_pdf_sha1": "02f86109cb69", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00061', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-ea33d64d', 'sub-elementary-6e11b43e-02', NULL, 'single_choice', '依據現行原住民族教育法第 7 條明定：「中央教育主管機關與中央原住民族主管機關應共同召開原住民 族教育政策會，進行下列原住民族教育政策規劃之諮詢」，下列何者不是諮詢項目？', '["原住民族教育體系", "原住民族職業訓練計畫", "建構原住民族知識體系中長程計畫", "原住民族教育發展計畫"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:55+00:00", "source_pdf_sha1": "c52cfd10ec2a", "answer_pdf_sha1": "02f86109cb69", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00062', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-ea33d64d', 'sub-elementary-6e11b43e-02', NULL, 'single_choice', '依照原住民族教育法規定，國民教育階段之原住民重點學校，於徵得設籍於該學區成年原住民多少比例人 口數以上書面同意，始得合併或停辦學校？', '["二分之一", "三分之二", "四分之三", "五分之三"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:55+00:00", "source_pdf_sha1": "c52cfd10ec2a", "answer_pdf_sha1": "02f86109cb69", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00063', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-ea33d64d', 'sub-elementary-6e11b43e-02', NULL, 'single_choice', '依照原住民族教育法規定，中央政府應寬列預算，專款辦理原住民族教育；其比率，合計不得少於中央教 育主管機關預算總額之多少比例，並依其需求逐年成長：', '["1.9%", "2.5%", "1.2%", "3.6%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:55+00:00", "source_pdf_sha1": "c52cfd10ec2a", "answer_pdf_sha1": "02f86109cb69", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00064', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-ea33d64d', 'sub-elementary-6e11b43e-02', NULL, 'single_choice', '依照原住民族教育法規定，地方政府應設立任務編組性質之單位，辦理原住民族教育課程、教材與教學方 法之研發及推廣，並協助其主管之學校，發展符合當地原住民族之民族教育課程規劃與評量方式，及其他 原住民族教育事務。請問該單位名稱為何？', '["原住民族課程研發中心", "原住民族教師研習中心", "原住民族教育資源中心", "原住民族教科書編輯中心"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:55+00:00", "source_pdf_sha1": "c52cfd10ec2a", "answer_pdf_sha1": "02f86109cb69", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00065', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-ea33d64d', 'sub-elementary-6e11b43e-02', NULL, 'single_choice', '依照原住民族教育法第43條規定，各級教育主管機關推動教育政策，應促進全體國民認識與尊重原住民 族，並得鼓勵、補助非營利之機構、法人或團體，對社會大眾進行原住民族及多元文化教育。政府機關、 公營事業機構及政府捐助基金累計超過百分之多少之財團法人，應規劃實施原住民族及多元文化教育相 關課程或活動，並鼓勵其員工參與？', '["百分之二十", "百分之三十", "百分之四十", "百分之五十"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:55+00:00", "source_pdf_sha1": "c52cfd10ec2a", "answer_pdf_sha1": "02f86109cb69", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00066', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-ea33d64d', 'sub-elementary-6e11b43e-02', NULL, 'single_choice', '依照原住民族教育法規定，原住民幼兒申請下列何種單位就讀沒有優先權？', '["公立幼兒園", "私立幼兒園", "非營利幼兒園", "社區或部落互助教保服務中心"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:55+00:00", "source_pdf_sha1": "c52cfd10ec2a", "answer_pdf_sha1": "02f86109cb69", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00067', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-ea33d64d', 'sub-elementary-6e11b43e-02', NULL, 'single_choice', '依照原住民族健康法規定，中央教育主管機關應鼓勵各健康照護相關科系之大專校院課程內容，融入原住 民族健康事務之文化安全相關課程之教學或學習活動。何者不是該法所稱文化安全的定義？', '["以原住民族知識體系為主", "確保原住民族於健康照護領域中獲得公平、適當之健康服務", "使其身分或文化得到適足保障", "使健保資源依照原住民族人口分配"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:55+00:00", "source_pdf_sha1": "c52cfd10ec2a", "answer_pdf_sha1": "02f86109cb69", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00068', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-ea33d64d', 'sub-elementary-6e11b43e-02', NULL, 'single_choice', '依照原住民族健康法規定，為落實及推動原住民族健康政策，中央主管機關應遴聘（派）原住民族代表、 有關機關代表及原住民族健康照護專家學者，召開原住民族健康政策會，政策會由下列何者擔任召集人？', '["原住民族委員會主任委員", "衛生福利部部長", "總統府秘書長", "行政院院長"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:55+00:00", "source_pdf_sha1": "c52cfd10ec2a", "answer_pdf_sha1": "02f86109cb69", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL)
